sql:
SELECT COUNT(*)
  FROM site_maintenance
  WHERE site_id = 1 AND completion_date IS NOT NULL;

SELECT next_inspection_date
FROM site_inspections
WHERE site_id = 1;

SELECT COUNT(*) AS document_count
FROM site_documents
WHERE site_id = 1;

SELECT MAX(activity_date) AS latest_maintenance_date
FROM site_maintenance
WHERE site_id = 1;

SELECT COUNT(*) AS total_inspections
FROM site_inspections
WHERE site_id = 1;

SELECT image_id, image_type
FROM site_images
WHERE image_type = 'photograph';

SELECT structure_name 
FROM heritage_sites 
ORDER BY structure_name;

SELECT structure_name
FROM heritage_sites
ORDER BY structure_name ASC;

SELECT COUNT(*) AS image_count
FROM site_images
WHERE site_id = 1;

SELECT structure_name, built_year
FROM heritage_sites
ORDER BY built_year DESC;

external_knowledge:
- "Recent" is defined here as within the last year from the current date; 
- "Condition rating" is an assessment of the site's state (e.g., good, fair, poor);
- Sites with "at least one maintenance activity" are considered to have undergone some form of upkeep or repair.

